// dashboards/platform-slo.jsonnet — the platform team monitors itself
local grafana = import 'grafonnet/grafana.libsonnet';
local panels = import 'genai-panels.libsonnet';

grafana.dashboard.new('Observability Platform SLOs')
+ grafana.dashboard.withUid('obs-platform-slos')
+ grafana.dashboard.withPanels([

  // Collector ingest success rate (SLO: 99.9%)
  panels.statPanel(
    title='Collector Ingest Availability',
    expr='1 - rate(otelcol_receiver_refused_spans[5m]) / rate(otelcol_receiver_accepted_spans[5m])',
    thresholds=[{value: 0.999, color: 'green'}, {value: 0.99, color: 'yellow'}, {value: 0, color: 'red'}],
  ),

  // Loki query P95 latency
  panels.timeseriesPanel(
    title='Loki Query Latency P95',
    expr='histogram_quantile(0.95, sum(rate(loki_request_duration_seconds_bucket{route="/loki/api/v1/query_range"}[5m])) by (le))',
    unit='s',
  ),

  // SDK adoption: fraction of spans with gen_ai.system attribute
  panels.statPanel(
    title='SDK Adoption Rate',
    expr='count(count by (service_name) (gen_ai_request_duration_seconds_count)) / count(count by (service_name) (http_requests_total))',
    unit='percentunit',
  ),
])
